import { MercadoPagoConfig, Payment } from "mercadopago"

const client = new MercadoPagoConfig({
  accessToken: process.env.NEXT_PUBLIC_MP_ACCESS_TOKEN,
  options: {
    timeout: 5000,
    idempotencyKey: generateIdempotencyKey() // Importante para evitar pagos duplicados
  }
})

function generateIdempotencyKey() {
  return Date.now().toString() + '-' + Math.random().toString(36).substring(7)
}

export async function POST(req) {
  try {
    const body = await req.json()
    console.log("📦 Datos recibidos:", JSON.stringify(body, null, 2))

    // Validaciones exhaustivas
    if (!body.transaction_amount) {
      return Response.json({ error: true, message: "Monto no proporcionado" }, { status: 400 })
    }

    if (!body.token) {
      return Response.json({ error: true, message: "Token de tarjeta no proporcionado" }, { status: 400 })
    }

    if (!body.payment_method_id) {
      return Response.json({ error: true, message: "Método de pago no identificado" }, { status: 400 })
    }

    if (!body.payer?.email) {
      return Response.json({ error: true, message: "Email del pagador no proporcionado" }, { status: 400 })
    }

    const payment = new Payment(client)

    // Construcción del pago con todos los campos posibles
    const paymentData = {
      transaction_amount: Number(body.transaction_amount),
      token: body.token,
      description: body.description || "Compra en tienda",
      installments: Number(body.installments || 1),
      payment_method_id: body.payment_method_id,
      issuer_id: body.issuer_id || undefined, // Solo enviar si existe
      payer: {
        email: body.payer.email,
        identification: body.payer.identification ? {
          type: body.payer.identification.type || "DNI",
          number: body.payer.identification.number
        } : undefined,
        first_name: body.payer.first_name || "Comprador",
        last_name: body.payer.last_name || ""
      },
      additional_info: {
        items: [
          {
            id: "item-1",
            title: "Producto",
            quantity: 1,
            unit_price: Number(body.transaction_amount)
          }
        ]
      }
    }

    // Limpiar undefined
    Object.keys(paymentData).forEach(key => {
      if (paymentData[key] === undefined) {
        delete paymentData[key]
      }
    })

    console.log("🚀 Enviando a MercadoPago:", JSON.stringify(paymentData, null, 2))

    const result = await payment.create({ body: paymentData })
    
    console.log("✅ Respuesta MP:", {
      status: result.status,
      id: result.id,
      detail: result.status_detail
    })

    return Response.json({
      success: true,
      status: result.status,
      id: result.id,
      detail: result.status_detail
    })

  } catch (error) {
    console.error("❌ Error:", {
      message: error.message,
      cause: error.cause,
      status: error.status,
      response: error.response?.data
    })

    return Response.json({
      success: false,
      error: true,
      message: error.message,
      cause: error.cause,
      details: error.response?.data || {}
    }, { status: error.status || 500 })
  }
}